<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Snake</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #10141c;
      --panel: #191f2b;
      --panel-light: #232c3b;
      --text: #ecf3ff;
      --muted: #9eabc0;
      --accent: #54e38e;
      --accent-dark: #26965a;
      --food: #ff6680;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      background:
        radial-gradient(circle at top, #202b3d 0, var(--bg) 48%, #0b0e14 100%);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    main {
      width: min(92vw, 560px);
      padding: 24px;
      border: 1px solid #2b3547;
      border-radius: 20px;
      background: rgba(25, 31, 43, 0.94);
      box-shadow: 0 20px 60px rgba(0, 0, 0, 0.4);
      text-align: center;
    }

    h1 {
      margin: 0 0 14px;
      font-size: 2rem;
      letter-spacing: 0.08em;
      text-transform: uppercase;
    }

    .info {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin: 0 auto 16px;
      max-width: 480px;
      color: var(--muted);
      font-size: 1rem;
    }

    #score {
      color: var(--accent);
      font-size: 1.35rem;
      font-weight: 800;
    }

    #snake {
      display: block;
      width: 480px;
      height: 480px;
      max-width: 100%;
      aspect-ratio: 1;
      margin: 0 auto;
      border: 3px solid #334158;
      border-radius: 12px;
      background: #111823;
      box-shadow: inset 0 0 28px rgba(0, 0, 0, 0.45), 0 8px 24px rgba(0, 0, 0, 0.25);
    }

    .controls {
      display: flex;
      justify-content: center;
      gap: 10px;
      margin-top: 18px;
    }

    button {
      border: 1px solid #3b4960;
      border-radius: 9px;
      padding: 10px 17px;
      color: var(--text);
      background: var(--panel-light);
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: transform 0.12s, background 0.12s, border-color 0.12s;
    }

    button:hover {
      background: #2c394d;
      border-color: #5b6d88;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    #start {
      color: #06170d;
      background: var(--accent);
      border-color: var(--accent);
    }

    #start:hover {
      background: #78efa7;
      border-color: #78efa7;
    }

    #message {
      min-height: 1.4em;
      margin: 13px 0 0;
      color: var(--muted);
      font-size: 0.9rem;
    }

    @media (max-width: 500px) {
      main {
        padding: 16px;
        border-radius: 14px;
      }

      h1 {
        font-size: 1.6rem;
      }

      .controls button {
        padding: 9px 12px;
      }
    }
  </style>
</head>
<body>
  <main>
    <h1>Snake</h1>
    <div class="info">
      <span>Arrow keys to steer</span>
      <span>Score: <strong id="score">0</strong></span>
    </div>

    <canvas id="snake" width="480" height="480" aria-label="Snake game board"></canvas>

    <div class="controls">
      <button id="start" type="button">Start</button>
      <button id="pause" type="button">Pause</button>
      <button id="reset" type="button">Reset</button>
    </div>
    <p id="message">Press Start or an arrow key to play</p>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("snake");
      const ctx = canvas.getContext("2d");
      const scoreEl = document.getElementById("score");
      const messageEl = document.getElementById("message");
      const startBtn = document.getElementById("start");
      const pauseBtn = document.getElementById("pause");
      const resetBtn = document.getElementById("reset");

      const w = 20;
      const h = 20;
      const cell = canvas.width / w;
      const directions = {
        up: [0, -1],
        down: [0, 1],
        left: [-1, 0],
        right: [1, 0]
      };

      let body = [];
      let foodPos = [0, 0];
      let heading = "right";
      let queuedHeading = "right";
      let points = 0;
      let isAlive = true;
      let timer = null;

      function same(a, b) {
        return a[0] === b[0] && a[1] === b[1];
      }

      function opposite(a, b) {
        return directions[a][0] === -directions[b][0] &&
               directions[a][1] === -directions[b][1];
      }

      function freeCell() {
        const free = [];
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            if (!body.some(part => part[0] === x && part[1] === y)) {
              free.push([x, y]);
            }
          }
        }
        return free.length ? free[Math.floor(Math.random() * free.length)] : null;
      }

      function placeRandomFood() {
        const spot = freeCell();
        if (spot) foodPos = spot;
      }

      function drawRoundedRect(x, y, width, height, radius) {
        const r = Math.min(radius, width / 2, height / 2);
        ctx.beginPath();
        ctx.roundRect(x, y, width, height, r);
        ctx.fill();
      }

      function draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = "#111823";
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.strokeStyle = "rgba(117, 139, 169, 0.09)";
        ctx.lineWidth = 1;
        for (let x = 1; x < w; x++) {
          ctx.beginPath();
          ctx.moveTo(x * cell + 0.5, 0);
          ctx.lineTo(x * cell + 0.5, canvas.height);
          ctx.stroke();
        }
        for (let y = 1; y < h; y++) {
          ctx.beginPath();
          ctx.moveTo(0, y * cell + 0.5);
          ctx.lineTo(canvas.width, y * cell + 0.5);
          ctx.stroke();
        }

        const fx = foodPos[0] * cell + cell / 2;
        const fy = foodPos[1] * cell + cell / 2;
        ctx.fillStyle = "rgba(255, 102, 128, 0.18)";
        ctx.beginPath();
        ctx.arc(fx, fy, cell * 0.39, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = "#ff6680";
        ctx.beginPath();
        ctx.arc(fx, fy, cell * 0.25, 0, Math.PI * 2);
        ctx.fill();

        body.forEach((part, index) => {
          const pad = index === 0 ? 2 : 3;
          ctx.fillStyle = index === 0 ? "#6cf0a1" : "#35bd73";
          drawRoundedRect(
            part[0] * cell + pad,
            part[1] * cell + pad,
            cell - pad * 2,
            cell - pad * 2,
            5
          );
        });

        if (body.length) {
          const head = body[0];
          const x = head[0] * cell;
          const y = head[1] * cell;
          ctx.fillStyle = "#102219";

          let eyes;
          if (heading === "left") eyes = [[x + 7, y + 7], [x + 7, y + 17]];
          else if (heading === "right") eyes = [[x + 17, y + 7], [x + 17, y + 17]];
          else if (heading === "up") eyes = [[x + 7, y + 7], [x + 17, y + 7]];
          else eyes = [[x + 7, y + 17], [x + 17, y + 17]];

          eyes.forEach(([ex, ey]) => {
            ctx.beginPath();
            ctx.arc(ex, ey, 2, 0, Math.PI * 2);
            ctx.fill();
          });
        }

        if (!isAlive) {
          ctx.fillStyle = "rgba(5, 8, 13, 0.56)";
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.fillStyle = "#ffffff";
          ctx.font = "700 28px system-ui, sans-serif";
          ctx.textAlign = "center";
          ctx.fillText("Game Over", canvas.width / 2, canvas.height / 2);
        }
      }

      function reset() {
        stopTimer();
        const cx = Math.floor(w / 2);
        const cy = Math.floor(h / 2);
        body = [[cx, cy], [cx - 1, cy], [cx - 2, cy]];
        heading = "right";
        queuedHeading = "right";
        points = 0;
        isAlive = true;
        scoreEl.textContent = points;
        messageEl.textContent = "Press Start or an arrow key to play";
        placeRandomFood();
        draw();
      }

      function tick() {
        if (!isAlive) return;

        heading = queuedHeading;
        const [dx, dy] = directions[heading];
        const head = body[0];
        const next = [head[0] + dx, head[1] + dy];
        const eating = same(next, foodPos);

        if (next[0] < 0 || next[0] >= w || next[1] < 0 || next[1] >= h) {
          isAlive = false;
          stopTimer();
          messageEl.textContent = "You hit the wall — press Reset to try again";
          draw();
          return;
        }

        const collisionBody = eating ? body : body.slice(0, -1);
        if (collisionBody.some(part => same(part, next))) {
          isAlive = false;
          stopTimer();
          messageEl.textContent = "You ran into yourself — press Reset to try again";
          draw();
          return;
        }

        body.unshift(next);

        if (eating) {
          points++;
          scoreEl.textContent = points;
          placeRandomFood();
        } else {
          body.pop();
        }

        draw();
      }

      function setDir(dir) {
        if (!directions[dir] || !isAlive) return;
        if (opposite(dir, queuedHeading)) return;
        queuedHeading = dir;
        if (!timer) startTimer();
      }

      function setFood(x, y) {
        x = Number(x);
        y = Number(y);
        if (Number.isInteger(x) && Number.isInteger(y) &&
            x >= 0 && x < w && y >= 0 && y < h) {
          foodPos = [x, y];
          draw();
        }
      }

      function startTimer() {
        if (timer || !isAlive) return;
        timer = setInterval(tick, 125);
        messageEl.textContent = "Playing";
      }

      function stopTimer() {
        if (timer) {
          clearInterval(timer);
          timer = null;
        }
      }

      document.addEventListener("keydown", event => {
        const keyMap = {
          ArrowUp: "up",
          ArrowDown: "down",
          ArrowLeft: "left",
          ArrowRight: "right"
        };
        if (keyMap[event.key]) {
          event.preventDefault();
          setDir(keyMap[event.key]);
        }
      });

      startBtn.addEventListener("click", startTimer);
      pauseBtn.addEventListener("click", () => {
        stopTimer();
        if (isAlive) messageEl.textContent = "Paused";
      });
      resetBtn.addEventListener("click", reset);

      window.game = {
        w,
        h,
        reset,
        tick,
        setDir,
        setFood,
        snake: () => body.map(part => [part[0], part[1]]),
        food: () => [foodPos[0], foodPos[1]],
        alive: () => isAlive,
        score: () => points
      };

      reset();
    })();
  </script>
</body>
</html>
